@contextmanager
def get_db_connection():
    """Context manager for database connections with APM instrumentation"""
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    try:
        yield conn
    finally:
        conn.close()

@app.before_request
def before_request():
    """Add custom context to APM transactions"""
    client = get_client()
    if client:
        client.begin_transaction('request')
        # Add custom labels and user context
        if request.headers.get('X-User-ID'):
            client.context.set_user(
                user_id=request.headers.get('X-User-ID'),
                username=request.headers.get('X-Username', 'anonymous'),
                email=request.headers.get('X-User-Email', '')
            )
        
        # Add custom context
        client.context.set_custom({
            'request_path': request.path,
            'request_method': request.method,
            'user_agent': request.headers.get('User-Agent', ''),
            'remote_addr': request.remote_addr
        })

@app.after_request
def after_request(response):
    """Add response context to APM transactions"""
    client = get_client()
    if client:
        client.context.set_custom({
            'response_status': response.status_code,
            'response_content_length': response.content_length
        })
    return response

