@app.route('/users', methods=['POST'])
def create_user():
    """Create a new user"""
    data = request.get_json()
    
    with capture_span('validate.user_data', 'app'):
        if not data or 'username' not in data or 'email' not in data:
            return jsonify({'error': 'Missing required fields'}), 400
    
    with capture_span('database.insert.user', 'db.sqlite',
                     {'db.statement': f'INSERT INTO users (username, email) VALUES ({data["username"]}, {data["email"]})'}):
        try:
            with get_db_connection() as conn:
                cursor = conn.cursor()
                cursor.execute('INSERT INTO users (username, email) VALUES (?, ?)',
                             (data['username'], data['email']))
                conn.commit()
                user_id = cursor.lastrowid
        except sqlite3.IntegrityError as e:
            logger.error(f"Database integrity error: {e}")
            client = get_client()
            if client:
                client.capture_exception()
            return jsonify({'error': 'Username already exists'}), 409
    
    return jsonify({'user_id': user_id, 'username': data['username']}), 201

