@app.route('/orders', methods=['POST'])
def create_order():
    """Create a new order with complex business logic"""
    data = request.get_json()
    
    with capture_span('validate.order_data', 'app'):
        required_fields = ['user_id', 'product_id', 'quantity']
        if not all(field in data for field in required_fields):
            return jsonify({'error': 'Missing required fields'}), 400
    
    user_id = data['user_id']
    product_id = data['product_id']
    quantity = data['quantity']
    
    # Validate user exists
    with capture_span('database.query.validate_user', 'db.sqlite'):
        with get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute('SELECT id FROM users WHERE id = ?', (user_id,))
            if cursor.fetchone() is None:
                return jsonify({'error': 'User not found'}), 404
    
    # Get product and check stock
    with capture_span('database.query.get_product', 'db.sqlite'):
        with get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM products WHERE id = ?', (product_id,))
            product = cursor.fetchone()
            
            if product is None:
                return jsonify({'error': 'Product not found'}), 404
            
            if product['stock'] < quantity:
                return jsonify({'error': 'Insufficient stock'}), 400
    
    # Calculate total price
    with capture_span('calculate.total_price', 'app'):
        total_price = product['price'] * quantity
        # Simulate some processing time
        time.sleep(0.1)
    
    # Create order and update stock
    with capture_span('database.transaction.create_order', 'db.sqlite'):
        with get_db_connection() as conn:
            cursor = conn.cursor()
            
            cursor.execute('''
                INSERT INTO orders (user_id, product_id, quantity, total_price)
                VALUES (?, ?, ?, ?)
            ''', (user_id, product_id, quantity, total_price))
            
            cursor.execute('''
                UPDATE products SET stock = stock - ? WHERE id = ?
            ''', (quantity, product_id))
            
            conn.commit()
            order_id = cursor.lastrowid
    
    return jsonify({
        'order_id': order_id,
        'total_price': total_price,
        'status': 'created'
    }), 201

@app.route('/orders/<int:user_id>', methods=['GET'])
def get_user_orders(user_id):
    """Get orders for a specific user with JOIN query"""
    query = '''
        SELECT 
            o.id as order_id,
            o.quantity,
            o.total_price,
            o.order_date,
            p.name as product_name,
            p.price as unit_price,
            u.username
        FROM orders o
        JOIN products p ON o.product_id = p.id
        JOIN users u ON o.user_id = u.id
        WHERE o.user_id = ?
        ORDER BY o.order_date DESC
    '''
    
    with capture_span('database.query.user_orders_join', 'db.sqlite', {'db.statement': query}):
        with get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(query, (user_id,))
            orders = [dict(row) for row in cursor.fetchall()]
    
    return jsonify({'orders': orders, 'count': len(orders)})

