@app.route('/error-test', methods=['GET'])
def error_test():
    """Endpoint to test error tracking"""
    error_type = request.args.get('type', 'generic')
    
    client = get_client()
    
    if error_type == 'database':
        with capture_span('database.error_test', 'db.sqlite'):
            try:
                with get_db_connection() as conn:
                    cursor = conn.cursor()
                    cursor.execute('SELECT * FROM non_existent_table')
            except sqlite3.OperationalError as e:
                if client:
                    client.capture_exception()
                return jsonify({'error': str(e)}), 500
    
    elif error_type == 'validation':
        try:
            raise ValueError("Invalid input data provided")
        except ValueError as e:
            if client:
                client.capture_exception()
            return jsonify({'error': str(e)}), 400
    
    elif error_type == 'division':
        try:
            result = 100 / 0
        except ZeroDivisionError as e:
            if client:
                client.capture_exception()
            return jsonify({'error': 'Division by zero'}), 500
    
    else:
        try:
            raise Exception("Generic error for testing")
        except Exception as e:
            if client:
                client.capture_exception()
            return jsonify({'error': str(e)}), 500

@app.route('/custom-transaction', methods=['POST'])
def custom_transaction():
    """Endpoint demonstrating custom transaction creation"""
    client = get_client()
    
    if client:
        # Create a custom transaction
        client.begin_transaction('custom')
        
        try:
            data = request.get_json()
            
            # Add custom labels
            client.label(
                transaction_type='custom_business_logic',
                priority=data.get('priority', 'normal'),
                region=data.get('region', 'unknown')
            )
            
            # Custom span within transaction
            with capture_span('business_logic.process', 'app', 
                            {'operation': 'custom_processing', 'items': len(data.get('items', []))}):
                time.sleep(0.1)
                processed = len(data.get('items', []))
            
            client.end_transaction('custom_transaction', 'success')
            
            return jsonify({'processed': processed, 'status': 'success'})
        
        except Exception as e:
            client.end_transaction('custom_transaction', 'failure')
            client.capture_exception()
            return jsonify({'error': str(e)}), 500
    
    return jsonify({'processed': 0, 'status': 'no_apm'})

@app.route('/batch-process', methods=['POST'])
def batch_process():
    """Simulate batch processing with detailed instrumentation"""
    data = request.get_json()
    items = data.get('items', [])
    
    results = {
        'total': len(items),
        'processed': 0,
        'failed': 0,
        'details': []
    }
    
    for idx, item in enumerate(items):
        span_name = f'batch.process_item_{idx}'
        with capture_span(span_name, 'app', {'item_id': item.get('id', 'unknown')}):
            try:
                # Simulate processing
                time.sleep(random.uniform(0.01, 0.05))
                
                if random.random() > 0.9:  # 10% failure rate
                    raise ValueError(f"Processing failed for item {item.get('id')}")
                
                results['processed'] += 1
                results['details'].append({
                    'id': item.get('id'),
                    'status': 'success'
                })
            except Exception as e:
                results['failed'] += 1
                results['details'].append({
                    'id': item.get('id'),
                    'status': 'failed',
                    'error': str(e)
                })
                
                client = get_client()
                if client:
                    client.capture_exception()
    
    return jsonify(results)

